    };

    public WebhookProxyController(HttpClient httpClient)
    {
        _httpClient = httpClient;
        _httpClient.Timeout = TimeSpan.FromSeconds(30);
    }

    [HttpPost("{*path}")]
    public async Task<IActionResult> Proxy([FromRoute] string path, [FromBody] object body)
    {
        try
        {
            var targetUrl = Request.Headers["X-Target-Url"].ToString();
            
            if (string.IsNullOrEmpty(targetUrl))
            {
                return BadRequest("Target URL is required");
            }

            if (!IsValidUrl(targetUrl))
            {
                return BadRequest("Invalid target URL");
            }

            if (!IsAllowedHost(targetUrl))
            {
                return BadRequest("Host not allowed");
            }

            var requestMessage = new HttpRequestMessage
            {
                Method = new HttpMethod(Request.Method),
                RequestUri = new Uri(targetUrl)
            };

            foreach (var header in Request.Headers)
            {
                if (!requestMessage.Headers.TryAddWithoutValidation(header.Key, header.Value.ToArray()))
                {
                    requestMessage.Content?.Headers.TryAddWithoutValidation(header.Key, header.Value.ToArray());
                }
            }

            if (body != null && Request.ContentLength > 0)
            {
                var json = System.Text.Json.JsonSerializer.Serialize(body);
                requestMessage.Content = new StringContent(json, Encoding.UTF8, "application/json");
            }

            var response = await _httpClient.SendAsync(requestMessage);
            
            var responseContent = await response.Content.ReadAsStringAsync();
            
            return new ContentResult
            {
                Content = responseContent,
                StatusCode = (int)response.StatusCode,
