    private bool IsValidUrl(string url)
    {
        if (string.IsNullOrEmpty(url))
            return false;

        if (!Uri.IsWellFormedUriString(url, UriKind.Absolute))
            return false;

        var uri = new Uri(url);
        return uri.Scheme == Uri.UriSchemeHttp || uri.Scheme == Uri.UriSchemeHttps;
