public static class IPAddressExtensions
{
    public static bool IsPrivate(this IPAddress ip)
    {
        if (ip.IsLoopback) return true;
        
        var bytes = ip.GetAddressBytes();
        
        // Private ranges
        if (bytes[0] == 10) return true;
